'use client'

import OrientalDashboardLayout from '@/components/layouts/OrientalDashboardLayout'
import { Users, TrendingUp, Shield, Activity, DollarSign, UserPlus } from 'lucide-react'

export default function AdminDashboard() {
  return (
    <OrientalDashboardLayout role="admin">
      {/* Welcome Section */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">
          Painel Administrativo 🏯
        </h1>
        <p className="text-gray-600">
          Visão holística e controle do ecossistema Nipo School.
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <div className="bg-white/80 backdrop-blur-sm p-6 rounded-2xl shadow-sm border border-purple-100 hover:shadow-md transition-all group">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-purple-50 rounded-xl group-hover:bg-purple-100 transition-colors">
              <Users className="w-6 h-6 text-purple-600" />
            </div>
            <span className="text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded-full flex items-center gap-1">
              <TrendingUp className="w-3 h-3" /> +12%
            </span>
          </div>
          <h3 className="text-gray-600 font-medium text-sm">Total de Alunos</h3>
          <p className="text-2xl font-bold text-gray-900 mt-1">1,234</p>
        </div>

        <div className="bg-white/80 backdrop-blur-sm p-6 rounded-2xl shadow-sm border border-purple-100 hover:shadow-md transition-all group">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-fuchsia-50 rounded-xl group-hover:bg-fuchsia-100 transition-colors">
              <DollarSign className="w-6 h-6 text-fuchsia-600" />
            </div>
            <span className="text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded-full flex items-center gap-1">
              <TrendingUp className="w-3 h-3" /> +5%
            </span>
          </div>
          <h3 className="text-gray-600 font-medium text-sm">Receita Mensal</h3>
          <p className="text-2xl font-bold text-gray-900 mt-1">R$ 45.2k</p>
        </div>

        <div className="bg-white/80 backdrop-blur-sm p-6 rounded-2xl shadow-sm border border-purple-100 hover:shadow-md transition-all group">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-violet-50 rounded-xl group-hover:bg-violet-100 transition-colors">
              <Activity className="w-6 h-6 text-violet-600" />
            </div>
            <span className="text-xs font-medium text-gray-500 bg-gray-50 px-2 py-1 rounded-full">
              Hoje
            </span>
          </div>
          <h3 className="text-gray-600 font-medium text-sm">Aulas Realizadas</h3>
          <p className="text-2xl font-bold text-gray-900 mt-1">89</p>
        </div>

        <div className="bg-white/80 backdrop-blur-sm p-6 rounded-2xl shadow-sm border border-purple-100 hover:shadow-md transition-all group">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-indigo-50 rounded-xl group-hover:bg-indigo-100 transition-colors">
              <Shield className="w-6 h-6 text-indigo-600" />
            </div>
            <span className="text-xs font-medium text-gray-500 bg-gray-50 px-2 py-1 rounded-full">
              Ativos
            </span>
          </div>
          <h3 className="text-gray-600 font-medium text-sm">Professores</h3>
          <p className="text-2xl font-bold text-gray-900 mt-1">24</p>
        </div>
      </div>

      {/* Recent Activity & Quick Actions */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Recent Registrations */}
        <div className="lg:col-span-2 bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2">
              <UserPlus className="w-5 h-5 text-purple-600" />
              Novos Cadastros
            </h2>
            <button className="text-sm text-purple-600 font-medium hover:text-purple-700">
              Ver todos
            </button>
          </div>
          
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider border-b border-gray-100">
                  <th className="pb-3 pl-2">Usuário</th>
                  <th className="pb-3">Plano</th>
                  <th className="pb-3">Status</th>
                  <th className="pb-3">Data</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {[1, 2, 3, 4, 5].map((i) => (
                  <tr key={i} className="group hover:bg-purple-50/30 transition-colors">
                    <td className="py-3 pl-2">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-xs font-bold text-gray-600">
                          U{i}
                        </div>
                        <div>
                          <p className="font-medium text-gray-900 text-sm">Novo Usuário {i}</p>
                          <p className="text-xs text-gray-500">user{i}@email.com</p>
                        </div>
                      </div>
                    </td>
                    <td className="py-3 text-sm text-gray-600">Premium Mensal</td>
                    <td className="py-3">
                      <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-green-100 text-green-800">
                        Ativo
                      </span>
                    </td>
                    <td className="py-3 text-sm text-gray-500">Há 2 horas</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* System Health / Quick Actions */}
        <div className="space-y-6">
          <div className="bg-gradient-to-br from-purple-600 to-indigo-700 rounded-3xl p-6 text-white shadow-lg">
            <h3 className="font-bold text-lg mb-4">Ações Rápidas</h3>
            <div className="space-y-3">
              <button className="w-full bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/10 rounded-xl p-3 text-left transition-all flex items-center gap-3">
                <UserPlus className="w-5 h-5" />
                <span>Cadastrar Professor</span>
              </button>
              <button className="w-full bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/10 rounded-xl p-3 text-left transition-all flex items-center gap-3">
                <Activity className="w-5 h-5" />
                <span>Relatório de Sistema</span>
              </button>
              <button className="w-full bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/10 rounded-xl p-3 text-left transition-all flex items-center gap-3">
                <Shield className="w-5 h-5" />
                <span>Gerenciar Permissões</span>
              </button>
            </div>
          </div>

          <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-900 mb-4">Status do Sistema</h3>
            <div className="space-y-4">
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">Servidor API</span>
                  <span className="text-green-600 font-medium">99.9%</span>
                </div>
                <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden">
                  <div className="bg-green-500 h-full rounded-full w-[99%]"></div>
                </div>
              </div>
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">Banco de Dados</span>
                  <span className="text-green-600 font-medium">Normal</span>
                </div>
                <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden">
                  <div className="bg-purple-500 h-full rounded-full w-[45%]"></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </OrientalDashboardLayout>
  )
}
